731 RecurrenceDescriptor::isAnyOfPattern(Loop *Loop, PHINode *OrigPhi,
732                                      Instruction *I, InstDesc &Prev) {
733   // We must handle the select(cmp(),x,y) as a single instruction. Advance to
734   // the select.
735   if (match(I, m_OneUse(m_Cmp()))) {
736     if (auto *Select = dyn_cast<SelectInst>(*I->user_begin()))
737       return InstDesc(Select, Prev.getRecKind());
738   }
739 
740   if (!match(I, m_Select(m_Cmp(), m_Value(), m_Value())))
741     return InstDesc(false, I);
742 
743   SelectInst *SI = cast<SelectInst>(I);
744   Value *NonPhi = nullptr;
745 
746   if (OrigPhi == dyn_cast<PHINode>(SI->getTrueValue()))
747     NonPhi = SI->getFalseValue();
748   else if (OrigPhi == dyn_cast<PHINode>(SI->getFalseValue()))
749     NonPhi = SI->getTrueValue();
