1558     // The reduction using MinOrMaxPhiR needs adjusting to compute the correct
1559     // result:
1560     //  1. We need to find the last IV for which the condition based on the
1561     //     min/max recurrence is true,
1562     //  2. Compare the partial min/max reduction result to its final value and,
1563     //  3. Select the lanes of the partial FindLastIV reductions which
1564     //     correspond to the lanes matching the min/max reduction result.
1565     //
1566     // For example, this transforms
1567     // vp<%min.result> = compute-reduction-result ir<%min.val.next>
1568     // vp<%iv.rdx> = compute-reduction-result (smax) vp<%min.idx.next>
1569     // vp<%cmp> = icmp ne vp<%iv.rdx>, SENTINEL
1570     // vp<%find.iv.result> = select vp<%cmp>, vp<%iv.rdx>, ir<0>
1571     //
1572     // into:
1573     //
1574     // vp<min.result> = compute-reduction-result ir<%min.val.next>
1575     // vp<%final.min.cmp> = icmp eq ir<%min.val.next>, vp<min.result>
1576     // vp<%final.iv> = select vp<%final.min.cmp>, vp<%min.idx.next>, SENTINEL
1577     // vp<%iv.rdx> = compute-reduction-result (smax) vp<%final.iv>
1578     // vp<%cmp> = icmp ne vp<%iv.rdx>, SENTINEL
1579     // vp<%find.iv.result> = select vp<%cmp>, vp<%iv.rdx>, ir<0>
1580     //
1581     // Find the FindIV result pattern.
1582     auto *FindIVSelect = findFindIVSelect(FindIVPhiR->getBackedgeValue());
1583     auto *FindIVCmp = FindIVSelect->getOperand(0)->getDefiningRecipe();
1584     auto *FindIVRdxResult = cast<VPInstruction>(FindIVCmp->getOperand(0));
1585     assert(FindIVSelect->getParent() == MinOrMaxResult->getParent() &&
1586            "both results must be computed in the same block");
1587     MinOrMaxResult->moveBefore(*FindIVRdxResult->getParent(),
1588                                FindIVRdxResult->getIterator());
1589 
1590     VPBuilder B(FindIVRdxResult);
1591     VPValue *MinOrMaxExiting = MinOrMaxResult->getOperand(0);
1592     auto *FinalMinOrMaxCmp =
1593         B.createICmp(CmpInst::ICMP_EQ, MinOrMaxExiting, MinOrMaxResult);
1594     VPValue *Sentinel = FindIVCmp->getOperand(1);
1595     VPValue *LastIVExiting = FindIVRdxResult->getOperand(0);
1596     auto *FinalIVSelect =
1597         B.createSelect(FinalMinOrMaxCmp, LastIVExiting, Sentinel);
1598     FindIVRdxResult->setOperand(0, FinalIVSelect);
1599   }
