2866                                                VPCostContext &Ctx) const {
2867   RecurKind RdxKind = getRecurrenceKind();
2868   Type *ElementTy = Ctx.Types.inferScalarType(this);
2869   auto *VectorTy = cast<VectorType>(toVectorTy(ElementTy, VF));
2870   unsigned Opcode = RecurrenceDescriptor::getOpcode(RdxKind);
2871   FastMathFlags FMFs = getFastMathFlags();
2872   std::optional<FastMathFlags> OptionalFMF =
2873       ElementTy->isFloatingPointTy() ? std::make_optional(FMFs) : std::nullopt;
2874 
2875   if (isPartialReduction()) {
2876     InstructionCost CondCost = 0;
2877     if (isConditional()) {
2878       CmpInst::Predicate Pred = CmpInst::BAD_ICMP_PREDICATE;
2879       auto *CondTy = cast<VectorType>(
2880           toVectorTy(Ctx.Types.inferScalarType(getCondOp()), VF));
2881       CondCost = Ctx.TTI.getCmpSelInstrCost(Instruction::Select, VectorTy,
2882                                             CondTy, Pred, Ctx.CostKind);
2883     }
2884     return CondCost + Ctx.TTI.getPartialReductionCost(
2885                           Opcode, ElementTy, ElementTy, ElementTy, VF,
2886                           TTI::PR_None, TTI::PR_None, {}, Ctx.CostKind,
2887                           OptionalFMF);
2888   }
2889 
2890   // TODO: Support any-of reductions.
2891   assert(
2892       (!RecurrenceDescriptor::isAnyOfRecurrenceKind(RdxKind) ||
2893        ForceTargetInstructionCost.getNumOccurrences() > 0) &&
2894       "Any-of reduction not implemented in VPlan-based cost model currently.");
2895 
2896   // Note that TTI should model the cost of moving result to the scalar register
2897   // and the BinOp cost in the getMinMaxReductionCost().
2898   if (RecurrenceDescriptor::isMinMaxRecurrenceKind(RdxKind)) {
2899     Intrinsic::ID Id = getMinMaxReductionIntrinsicOp(RdxKind);
2900     return Ctx.TTI.getMinMaxReductionCost(Id, VectorTy, FMFs, Ctx.CostKind);
2901   }
2902 
2903   // Note that TTI should model the cost of moving result to the scalar register
2904   // and the BinOp cost in the getArithmeticReductionCost().
2905   return Ctx.TTI.getArithmeticReductionCost(Opcode, VectorTy, OptionalFMF,
2906                                             Ctx.CostKind);
