2909 VPExpressionRecipe::VPExpressionRecipe(
2910     ExpressionTypes ExpressionType,
2911     ArrayRef<VPSingleDefRecipe *> ExpressionRecipes)
2912     : VPSingleDefRecipe(VPRecipeBase::VPExpressionSC, {}, {}),
2913       ExpressionRecipes(ExpressionRecipes), ExpressionType(ExpressionType) {
2914   assert(!ExpressionRecipes.empty() && "Nothing to combine?");
2915   assert(
2916       none_of(ExpressionRecipes,
2917               [](VPSingleDefRecipe *R) { return R->mayHaveSideEffects(); }) &&
2918       "expression cannot contain recipes with side-effects");
2919 
2920   // Maintain a copy of the expression recipes as a set of users.
2921   SmallPtrSet<VPUser *, 4> ExpressionRecipesAsSetOfUsers;
2922   for (auto *R : ExpressionRecipes)
2923     ExpressionRecipesAsSetOfUsers.insert(R);
2924 
2925   // Recipes in the expression, except the last one, must only be used by
2926   // (other) recipes inside the expression. If there are other users, external
2927   // to the expression, use a clone of the recipe for external users.
2928   for (VPSingleDefRecipe *R : reverse(ExpressionRecipes)) {
2929     if (R != ExpressionRecipes.back() &&
2930         any_of(R->users(), [&ExpressionRecipesAsSetOfUsers](VPUser *U) {
2931           return !ExpressionRecipesAsSetOfUsers.contains(U);
2932         })) {
2933       // There are users outside of the expression. Clone the recipe and use the
2934       // clone those external users.
2935       VPSingleDefRecipe *CopyForExtUsers = R->clone();
2936       R->replaceUsesWithIf(CopyForExtUsers, [&ExpressionRecipesAsSetOfUsers](
2937                                                 VPUser &U, unsigned) {
2938         return !ExpressionRecipesAsSetOfUsers.contains(&U);
2939       });
2940       CopyForExtUsers->insertBefore(R);
2941     }
2942     if (R->getParent())
2943       R->removeFromParent();
2944   }
2945 
2946   // Internalize all external operands to the expression recipes. To do so,
2947   // create new temporary VPValues for all operands defined by a recipe outside
2948   // the expression. The original operands are added as operands of the
2949   // VPExpressionRecipe itself.
2950   for (auto *R : ExpressionRecipes) {
2951     for (const auto &[Idx, Op] : enumerate(R->operands())) {
2952       auto *Def = Op->getDefiningRecipe();
2953       if (Def && ExpressionRecipesAsSetOfUsers.contains(Def))
2954         continue;
2955       addOperand(Op);
2956       LiveInPlaceholders.push_back(new VPSymbolicValue());
2957     }
2958   }
2959 
2960   // Replace each external operand with the first one created for it in
2961   // LiveInPlaceholders.
2962   for (auto *R : ExpressionRecipes)
2963     for (auto const &[LiveIn, Tmp] : zip(operands(), LiveInPlaceholders))
2964       R->replaceUsesOfWith(LiveIn, Tmp);
2965 }
