2967 void VPExpressionRecipe::decompose() {
2968   for (auto *R : ExpressionRecipes)
2969     // Since the list could contain duplicates, make sure the recipe hasn't
2970     // already been inserted.
2971     if (!R->getParent())
2972       R->insertBefore(this);
2973 
2974   for (const auto &[Idx, Op] : enumerate(operands()))
2975     LiveInPlaceholders[Idx]->replaceAllUsesWith(Op);
2976 
2977   replaceAllUsesWith(ExpressionRecipes.back());
2978   ExpressionRecipes.clear();
