1329 bool VPlanTransforms::handleFindLastReductions(VPlan &Plan) {
1330   if (Plan.hasScalarVFOnly())
1331     return false;
1332 
1333   // We want to create the following nodes:
1334   // vector.body:
1335   //   ...new WidenPHI recipe introduced to keep the mask value for the latest
1336   //      iteration where any lane was active.
1337   //   mask.phi = phi [ ir<false>, vector.ph ], [ vp<new.mask>, vector.body ]
1338   //   ...data.phi (a VPReductionPHIRecipe for a FindLast reduction) already
1339   //      exists, but needs updating to use 'new.data' for the backedge value.
1340   //   data.phi = phi ir<default.val>, vp<new.data>
1341   //
1342   //   ...'data' and 'compare' created by existing nodes...
1343   //
1344   //   ...new recipes introduced to determine whether to update the reduction
1345   //      values or keep the current one.
1346   //   any.active = i1 any-of ir<compare>
1347   //   new.mask = select vp<any.active>, ir<compare>, vp<mask.phi>
1348   //   new.data = select vp<any.active>, ir<data>, ir<data.phi>
1349   //
1350   // middle.block:
1351   //   ...extract-last-active replaces compute-reduction-result.
1352   //   result = extract-last-active vp<new.data>, vp<new.mask>, ir<default.val>
1353 
1354   for (auto &Phi : Plan.getVectorLoopRegion()->getEntryBasicBlock()->phis()) {
1355     auto *PhiR = dyn_cast<VPReductionPHIRecipe>(&Phi);
1356     if (!PhiR || !RecurrenceDescriptor::isFindLastRecurrenceKind(
1357                      PhiR->getRecurrenceKind()))
1358       continue;
1359 
1360     // Find the condition for the select/blend.
1361     auto *SelectR = cast<VPSingleDefRecipe>(&PhiR->getBackedgeRecipe());
1362     VPValue *Cond = nullptr, *Op1 = nullptr, *Op2 = nullptr;
1363 
1364     // If we're matching a blend rather than a select, there should be one
1365     // incoming value which is the data, then all other incoming values should
1366     // be the phi.
1367     auto MatchBlend = [&](VPRecipeBase *R) {
1368       auto *Blend = dyn_cast<VPBlendRecipe>(R);
1369       if (!Blend)
1370         return false;
1371       assert(!Blend->isNormalized() && "must run before blend normalizaion");
1372       unsigned NumIncomingDataValues = 0;
1373       for (unsigned I = 0; I < Blend->getNumIncomingValues(); ++I) {
1374         VPValue *Incoming = Blend->getIncomingValue(I);
1375         if (Incoming != PhiR) {
1376           ++NumIncomingDataValues;
1377           Cond = Blend->getMask(I);
1378           Op1 = Incoming;
1379           Op2 = PhiR;
1380         }
1381       }
1382       return NumIncomingDataValues == 1;
1383     };
1384 
1385     if (!match(SelectR,
1386                m_Select(m_VPValue(Cond), m_VPValue(Op1), m_VPValue(Op2))) &&
1387         !MatchBlend(SelectR))
1388       return false;
1389 
1390     // Add mask phi.
1391     VPBuilder Builder = VPBuilder::getToInsertAfter(PhiR);
1392     auto *MaskPHI = new VPWidenPHIRecipe(nullptr, /*Start=*/Plan.getFalse());
1393     Builder.insert(MaskPHI);
1394 
1395     // Add select for mask.
1396     Builder.setInsertPoint(SelectR);
1397 
1398     if (Op1 == PhiR) {
1399       // Normalize to selecting the data operand when the condition is true by
1400       // swapping operands and negating the condition.
1401       std::swap(Op1, Op2);
1402       Cond = Builder.createNot(Cond);
1403     }
1404     assert(Op2 == PhiR && "data value must be selected if Cond is true");
1405 
1406     VPValue *AnyOf = Builder.createNaryOp(VPInstruction::AnyOf, {Cond});
1407     VPValue *MaskSelect = Builder.createSelect(AnyOf, Cond, MaskPHI);
1408     MaskPHI->addOperand(MaskSelect);
1409 
1410     // Replace select for data.
1411     VPValue *DataSelect =
1412         Builder.createSelect(AnyOf, Op1, Op2, SelectR->getDebugLoc());
1413     SelectR->replaceAllUsesWith(DataSelect);
1414     SelectR->eraseFromParent();
1415 
1416     // Find final reduction computation and replace it with an
1417     // extract.last.active intrinsic.
1418     auto *RdxResult =
1419         vputils::findUserOf<VPInstruction::ComputeReductionResult>(DataSelect);
1420     // TODO: Handle tail-folding.
1421     if (!RdxResult)
1422       return false;
1423     Builder.setInsertPoint(RdxResult);
1424     auto *ExtractLastActive =
1425         Builder.createNaryOp(VPInstruction::ExtractLastActive,
1426                              {DataSelect, MaskSelect, PhiR->getStartValue()},
1427                              RdxResult->getDebugLoc());
1428     RdxResult->replaceAllUsesWith(ExtractLastActive);
1429     RdxResult->eraseFromParent();
1430   }
1431 
1432   return true;
1433 }
