1435 bool VPlanTransforms::handleMultiUseReductions(VPlan &Plan) {
1436   for (auto &PhiR : make_early_inc_range(
1437            Plan.getVectorLoopRegion()->getEntryBasicBlock()->phis())) {
1438     auto *MinOrMaxPhiR = dyn_cast<VPReductionPHIRecipe>(&PhiR);
1439     // TODO: check for multi-uses in VPlan directly.
1440     if (!MinOrMaxPhiR || !MinOrMaxPhiR->hasUsesOutsideReductionChain())
1441       continue;
1442 
1443     // MinOrMaxPhiR has users outside the reduction cycle in the loop. Check if
1444     // the only other user is a FindLastIV reduction. MinOrMaxPhiR must have
1445     // exactly 2 users:
1446     // 1) the min/max operation of the reduction cycle, and
1447     // 2) the compare of a FindLastIV reduction cycle. This compare must match
1448     // the min/max operation - comparing MinOrMaxPhiR with the operand of the
1449     // min/max operation, and be used only by the select of the FindLastIV
1450     // reduction cycle.
1451     RecurKind RdxKind = MinOrMaxPhiR->getRecurrenceKind();
1452     assert(
1453         RecurrenceDescriptor::isIntMinMaxRecurrenceKind(RdxKind) &&
1454         "only min/max recurrences support users outside the reduction chain");
1455 
1456     auto *MinOrMaxOp =
1457         dyn_cast<VPRecipeWithIRFlags>(MinOrMaxPhiR->getBackedgeValue());
1458     if (!MinOrMaxOp)
1459       return false;
1460 
1461     // Check that MinOrMaxOp is a VPWidenIntrinsicRecipe or VPReplicateRecipe
1462     // with an intrinsic that matches the reduction kind.
1463     Intrinsic::ID ExpectedIntrinsicID = getMinMaxReductionIntrinsicOp(RdxKind);
1464     if (!match(MinOrMaxOp, m_Intrinsic(ExpectedIntrinsicID)))
1465       return false;
1466 
1467     // MinOrMaxOp must have 2 users: 1) MinOrMaxPhiR and 2)
1468     // ComputeReductionResult.
1469     assert(MinOrMaxOp->getNumUsers() == 2 &&
1470            "MinOrMaxOp must have exactly 2 users");
1471     VPValue *MinOrMaxOpValue = MinOrMaxOp->getOperand(0);
1472     if (MinOrMaxOpValue == MinOrMaxPhiR)
1473       MinOrMaxOpValue = MinOrMaxOp->getOperand(1);
1474 
1475     VPValue *CmpOpA;
1476     VPValue *CmpOpB;
1477     CmpPredicate Pred;
1478     auto *Cmp = dyn_cast_or_null<VPRecipeWithIRFlags>(vputils::findUserOf(
1479         MinOrMaxPhiR, m_Cmp(Pred, m_VPValue(CmpOpA), m_VPValue(CmpOpB))));
1480     if (!Cmp || Cmp->getNumUsers() != 1 ||
1481         (CmpOpA != MinOrMaxOpValue && CmpOpB != MinOrMaxOpValue))
1482       return false;
1483 
1484     if (MinOrMaxOpValue != CmpOpB)
1485       Pred = CmpInst::getSwappedPredicate(Pred);
1486 
1487     // MinOrMaxPhiR must have exactly 2 users:
1488     // * MinOrMaxOp,
1489     // * Cmp (that's part of a FindLastIV chain).
1490     if (MinOrMaxPhiR->getNumUsers() != 2)
1491       return false;
1492 
1493     VPInstruction *MinOrMaxResult =
1494         vputils::findUserOf<VPInstruction::ComputeReductionResult>(MinOrMaxOp);
1495     assert(is_contained(MinOrMaxPhiR->users(), MinOrMaxOp) &&
1496            "one user must be MinOrMaxOp");
1497     assert(MinOrMaxResult &&
1498            "MinOrMaxOp must have a ComputeReductionResult user");
1499 
1500     // Cmp must be used by the select of a FindLastIV chain.
1501     VPValue *Sel = dyn_cast<VPSingleDefRecipe>(Cmp->getSingleUser());
1502     VPValue *IVOp, *FindIV;
1503     if (!Sel || Sel->getNumUsers() != 2 ||
1504         !match(Sel,
1505                m_Select(m_Specific(Cmp), m_VPValue(IVOp), m_VPValue(FindIV))))
1506       return false;
1507 
1508     if (!isa<VPReductionPHIRecipe>(FindIV)) {
1509       std::swap(FindIV, IVOp);
1510       Pred = CmpInst::getInversePredicate(Pred);
1511     }
1512 
1513     auto *FindIVPhiR = dyn_cast<VPReductionPHIRecipe>(FindIV);
1514     if (!FindIVPhiR || !RecurrenceDescriptor::isFindIVRecurrenceKind(
1515                            FindIVPhiR->getRecurrenceKind()))
1516       return false;
1517 
1518     // Check if FindIVPhiR is a FindLast pattern by checking the MinMaxKind
1519     // on its ComputeReductionResult. SMax/UMax indicates FindLast.
1520     VPInstruction *FindIVResult =
1521         vputils::findUserOf<VPInstruction::ComputeReductionResult>(
1522             FindIVPhiR->getBackedgeValue());
1523     assert(FindIVResult &&
1524            "must be able to retrieve the FindIVResult VPInstruction");
1525     RecurKind FindIVMinMaxKind = FindIVResult->getRecurKind();
1526     if (FindIVMinMaxKind != RecurKind::SMax &&
1527         FindIVMinMaxKind != RecurKind::UMax)
1528       return false;
1529 
1530     // TODO: Support cases where IVOp is the IV increment.
1531     if (!match(IVOp, m_TruncOrSelf(m_VPValue(IVOp))) ||
1532         !isa<VPWidenIntOrFpInductionRecipe>(IVOp))
1533       return false;
1534 
1535     CmpInst::Predicate RdxPredicate = [RdxKind]() {
1536       switch (RdxKind) {
1537       case RecurKind::UMin:
1538         return CmpInst::ICMP_UGE;
1539       case RecurKind::UMax:
1540         return CmpInst::ICMP_ULE;
1541       case RecurKind::SMax:
1542         return CmpInst::ICMP_SLE;
1543       case RecurKind::SMin:
1544         return CmpInst::ICMP_SGE;
1545       default:
1546         llvm_unreachable("unhandled recurrence kind");
1547       }
1548     }();
