218 /// Returns true if \p Phi is a min/max reduction matching \p Kind where \p Phi
219 /// is used outside the reduction chain. This is common for loops selecting the
220 /// index of a minimum/maximum value (argmin/argmax).
221 static bool isMinMaxReductionPhiWithUsersOutsideReductionChain(
222     PHINode *Phi, RecurKind Kind, Loop *TheLoop, RecurrenceDescriptor &RedDes) {
223   BasicBlock *Latch = TheLoop->getLoopLatch();
224   if (!Latch)
225     return false;
226 
227   assert(Phi->getNumIncomingValues() == 2 && "phi must have 2 incoming values");
228   Value *Inc = Phi->getIncomingValueForBlock(Latch);
229   if (Phi->hasOneUse() || !Inc->hasOneUse() ||
230       !RecurrenceDescriptor::isIntMinMaxRecurrenceKind(Kind))
231     return false;
232 
233   Value *A, *B;
234   bool IsMinMax = [&]() {
235     switch (Kind) {
236     case RecurKind::UMax:
237       return match(Inc, m_UMax(m_Value(A), m_Value(B)));
238     case RecurKind::UMin:
239       return match(Inc, m_UMin(m_Value(A), m_Value(B)));
240     case RecurKind::SMax:
241       return match(Inc, m_SMax(m_Value(A), m_Value(B)));
242     case RecurKind::SMin:
243       return match(Inc, m_SMin(m_Value(A), m_Value(B)));
244     default:
245       llvm_unreachable("all min/max kinds must be handled");
246     }
247   }();
248   if (!IsMinMax)
249     return false;
